import React from 'react';
import * as ReactDOMClient from 'react-dom/client';
import singleSpaReact from 'single-spa-react';
import { Provider } from 'react-redux';
import { store } from '../store/store';
import { CustomerForm } from '../components/dm/CustomerForm';
import type { CustomerCreateParcelProps } from './CustomerCreateParcel.types';

const TEST_ID = 'parcel-customer-create';

const CustomerCreateParcelInner: React.FC<CustomerCreateParcelProps> = ({
  initialName = '',
  defaultCustomerType = 'Customer',
  onSuccess,
  onCancel,
}) => (
  <CustomerForm
    testIdPrefix={TEST_ID}
    initialName={initialName}
    defaultCustomerType={defaultCustomerType}
    initFormName="create-customer"
    hideCompanyField
    onCancel={onCancel}
    onSaved={created => onSuccess({
      customerId: created.customerId,
      code: created.code,
      name: created.name,
      phone: created.phone,
      customerType: created.customerType,
      customerGroupId: created.customerGroupId,
    })}
  />
);

/** Parcel root — Redux Provider (separate React root from consumer MFE). */
export const CustomerCreateParcelRoot: React.FC<CustomerCreateParcelProps> = props => (
  <Provider store={store}>
    <CustomerCreateParcelInner {...props} />
  </Provider>
);

export const customerCreateParcelLifecycles = singleSpaReact({
  React,
  ReactDOMClient,
  rootComponent: CustomerCreateParcelRoot,
  errorBoundary(_err: Error) {
    return (
      <div style={{ padding: '1rem', color: '#c62828' }}>
        Lỗi form tạo đối tượng
      </div>
    );
  },
  renderType: 'createRoot',
});
