import React, { useState } from 'react';
import { Button, Modal, useViewMobileLayout } from '@linm-soft/common-components';
import styles from '../../styles/erpPage.module.css';

export interface CatalogListToolbarProps {
  testIdPrefix: string;
  canAdd?: boolean;
  canEdit?: boolean;
  canHistory?: boolean;
  canRename?: boolean;
  canDelete?: boolean;
  selectedCount?: number;
  onAdd?: () => void;
  onEdit?: () => void;
  onHistory?: () => void;
  onRefresh?: () => void;
  onRename?: () => void;
  onDelete?: () => void;
  /** Shared catalog: Đề xuất · Chờ duyệt — sau Làm mới · Lịch sử (trái). */
  sharedActions?: React.ReactNode;
  /** e.g. Sửa cấu hình cột — sau Làm mới. */
  extraLeftActions?: React.ReactNode;
}

/**
 * Sticky catalog action bar (single line).
 * Left (L→R): Làm mới · Lịch sử
 * Right (R→L): Thêm mới · Sửa · Xóa · Đổi mã
 * Filters live in `CatalogListShell` inner header — not here.
 */
export const CatalogListToolbar: React.FC<CatalogListToolbarProps> = ({
  testIdPrefix,
  canAdd = true,
  canEdit = false,
  canHistory = false,
  canRename = false,
  canDelete = false,
  selectedCount = 0,
  onAdd,
  onEdit,
  onHistory,
  onRefresh,
  onRename,
  onDelete,
  sharedActions,
  extraLeftActions,
}) => {
  const viewMobile = useViewMobileLayout();
  const [moreOpen, setMoreOpen] = useState(false);

  const leftActions = (
    <>
      <Button
        variant="secondary"
        size="sm"
        data-testid={`${testIdPrefix}-toolbar-refresh-btn`}
        onClick={onRefresh}
      >
        <i className="fas fa-sync-alt" /> Làm mới
      </Button>
      <Button
        variant="secondary"
        size="sm"
        disabled={!canHistory}
        data-testid={`${testIdPrefix}-toolbar-history-btn`}
        onClick={onHistory}
      >
        <i className="fas fa-history" /> Lịch sử
      </Button>
      {extraLeftActions}
      {sharedActions}
    </>
  );

  /** Right cluster: DOM L→R = Đổi mã · Xóa · Sửa · Thêm mới (Thêm ở mép phải). */
  const rightActions = (
    <>
      <Button
        variant="secondary"
        size="sm"
        disabled={!canRename}
        data-testid={`${testIdPrefix}-rename-code-btn`}
        onClick={onRename}
      >
        <i className="fas fa-exchange-alt" /> Đổi mã
      </Button>
      <Button
        variant="secondary"
        size="sm"
        disabled={!canDelete || selectedCount === 0}
        data-testid={`${testIdPrefix}-batch-delete-btn`}
        onClick={onDelete}
      >
        <i className="fas fa-trash" /> Xóa
        {selectedCount > 0 ? ` (${selectedCount})` : ''}
      </Button>
      <Button
        variant="secondary"
        size="sm"
        disabled={!canEdit}
        data-testid={`${testIdPrefix}-toolbar-edit-btn`}
        onClick={onEdit}
      >
        <i className="fas fa-edit" /> Sửa
      </Button>
      {canAdd && (
        <Button
          variant="primary"
          size="sm"
          data-testid={`${testIdPrefix}-toolbar-add-btn`}
          onClick={onAdd}
        >
          <i className="fas fa-plus" /> Thêm mới
        </Button>
      )}
    </>
  );

  return (
    <div className={styles.catalogToolbarSticky} data-testid={`${testIdPrefix}-catalog-toolbar`}>
      <div className={styles.catalogToolbarLine1}>
        <div className={styles.catalogToolbarLeft}>
          {viewMobile ? (
            <>
              <Button
                variant="secondary"
                size="sm"
                data-testid={`${testIdPrefix}-toolbar-more-btn`}
                onClick={() => setMoreOpen(true)}
              >
                <i className="fas fa-ellipsis-h" /> Thao tác
              </Button>
              <Modal
                isOpen={moreOpen}
                onClose={() => setMoreOpen(false)}
                title="Thao tác danh mục"
                size="sm"
              >
                <div className={styles.catalogToolbarMoreBody}>
                  {leftActions}
                  {sharedActions}
                  {rightActions}
                </div>
              </Modal>
            </>
          ) : (
            leftActions
          )}
        </div>
        <div className={styles.catalogToolbarRight}>
          {viewMobile ? null : rightActions}
        </div>
      </div>
    </div>
  );
};
