import React, { useEffect, useState } from 'react';
import { Button, Input, Modal, addToast } from '@linm-soft/common-components';
import styles from '../../styles/erpPage.module.css';

export interface CodeUsageImpactRow {
  tableName: string;
  entityLabel: string;
  estimatedCount: number;
}

export interface CatalogRenameCodeModalProps {
  testIdPrefix: string;
  isOpen: boolean;
  onClose: () => void;
  catalogKind: string;
  oldCode: string;
  oldName?: string;
  /** Fetch impact preview — BE `GET …/usage-impact` */
  fetchImpact?: (catalogKind: string, code: string, newCode: string) => Promise<CodeUsageImpactRow[]>;
  onSubmit: (newCode: string, mergeIfExists: boolean) => Promise<void>;
}

export const CatalogRenameCodeModal: React.FC<CatalogRenameCodeModalProps> = ({
  testIdPrefix,
  isOpen,
  onClose,
  catalogKind,
  oldCode,
  oldName,
  fetchImpact,
  onSubmit,
}) => {
  const [newCode, setNewCode] = useState('');
  const [impact, setImpact] = useState<CodeUsageImpactRow[]>([]);
  const [loadingImpact, setLoadingImpact] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [mergeIfExists, setMergeIfExists] = useState(false);

  useEffect(() => {
    if (!isOpen) return;
    setNewCode('');
    setImpact([]);
    setMergeIfExists(false);
  }, [isOpen, oldCode]);

  useEffect(() => {
    if (!isOpen || !newCode.trim() || !fetchImpact) {
      setImpact([]);
      return;
    }
    let cancelled = false;
    setLoadingImpact(true);
    const t = setTimeout(() => {
      fetchImpact(catalogKind, oldCode, newCode.trim().toUpperCase())
        .then(rows => { if (!cancelled) setImpact(rows); })
        .catch(() => { if (!cancelled) setImpact([]); })
        .finally(() => { if (!cancelled) setLoadingImpact(false); });
    }, 300);
    return () => { cancelled = true; clearTimeout(t); };
  }, [isOpen, catalogKind, oldCode, newCode, fetchImpact]);

  const totalAffected = impact.reduce((s, r) => s + r.estimatedCount, 0);

  const submit = async () => {
    const code = newCode.trim().toUpperCase();
    if (!code) {
      addToast({ message: 'Nhập mã mới', type: 'error' });
      return;
    }
    if (code === oldCode.toUpperCase()) {
      addToast({ message: 'Mã mới phải khác mã hiện tại', type: 'error' });
      return;
    }
    setSubmitting(true);
    try {
      await onSubmit(code, mergeIfExists);
      onClose();
    } catch (err: unknown) {
      addToast({
        message: err instanceof Error ? err.message : 'Đổi mã thất bại',
        type: 'error',
      });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Đổi mã danh mục"
      size="lg"
      data-testid={`${testIdPrefix}-rename-code-modal`}
    >
      <div className={styles.catalogModalBody}>
        <div className={styles.catalogWarningBanner}>
          <i className="fas fa-exclamation-triangle" />
          Thao tác không thể hoàn tác. Hệ thống sẽ thay thế mã ở mọi bảng đang sử dụng (job nền).
        </div>
        <div className={styles.field}>
          <label className={styles.label}>Mã hiện tại</label>
          <Input value={oldCode} disabled />
          {oldName ? <span className={styles.sharedCatalogHint}>{oldName}</span> : null}
        </div>
        <div className={styles.field}>
          <Input
            label="Mã mới *"
            value={newCode}
            className={styles.codeInput}
            data-testid={`${testIdPrefix}-rename-new-code`}
            onChange={e => setNewCode(e.target.value.toUpperCase())}
          />
        </div>
        {fetchImpact && newCode.trim() && (
          <div className={styles.catalogImpactBlock}>
            <h4 className={styles.catalogImpactTitle}>Ảnh hưởng ước tính</h4>
            {loadingImpact ? (
              <p className={styles.sharedCatalogHint}>Đang tải preview…</p>
            ) : impact.length === 0 ? (
              <p className={styles.sharedCatalogHint}>Chưa có dữ liệu tham chiếu hoặc chưa cấu hình impact.</p>
            ) : (
              <>
                <p>Tổng cộng khoảng <strong>{totalAffected}</strong> bản ghi sẽ được cập nhật.</p>
                <table className={styles.catalogImpactTable}>
                  <thead>
                    <tr>
                      <th>Bảng / loại</th>
                      <th>Mô tả</th>
                      <th>Số lượng</th>
                    </tr>
                  </thead>
                  <tbody>
                    {impact.map(row => (
                      <tr key={row.tableName}>
                        <td><code>{row.tableName}</code></td>
                        <td>{row.entityLabel}</td>
                        <td>{row.estimatedCount}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </>
            )}
          </div>
        )}
        <label className={styles.catalogMergePick}>
          <input
            type="checkbox"
            checked={mergeIfExists}
            onChange={e => setMergeIfExists(e.target.checked)}
          />
          Gộp nếu mã đích đã tồn tại (merge — cần xác nhận thêm từ BE)
        </label>
      </div>
      <div className={styles.modalFooterBar}>
        <Button variant="secondary" onClick={onClose} disabled={submitting}>Hủy</Button>
        <Button
          variant="primary"
          disabled={submitting}
          data-testid={`${testIdPrefix}-rename-submit`}
          onClick={() => void submit()}
        >
          {submitting ? 'Đang gửi…' : 'Xác nhận đổi mã'}
        </Button>
      </div>
    </Modal>
  );
};
