import { useCallback, useMemo, useState } from 'react';

export type CatalogSelectionMode = 'page' | 'all';

export interface UseCatalogListSelectionOptions<T> {
  rows: T[];
  totalCount: number;
  page: number;
  pageSize: number;
  getRowId: (row: T) => string;
  isRowSelectable?: (row: T) => boolean;
}

export interface UseCatalogListSelectionResult<T> {
  selectedIds: Set<string>;
  selectionMode: CatalogSelectionMode | null;
  selectedCount: number;
  /** Single row for Sửa / Lịch sử / Đổi mã — when exactly one id selected on page. */
  singleAnchor: T | null;
  isRowChecked: (row: T) => boolean;
  isPageAllSelected: boolean;
  toggleRow: (row: T, checked: boolean) => void;
  togglePageAll: () => void;
  selectAllInDatabase: () => void;
  clearSelection: () => void;
  /** Resolved ids for batch API — page ids or placeholder for all mode. */
  getBatchScope: () => { mode: CatalogSelectionMode | null; ids: string[] };
}

export function useCatalogListSelection<T>({
  rows,
  totalCount,
  page: _page,
  pageSize: _pageSize,
  getRowId,
  isRowSelectable = () => true,
}: UseCatalogListSelectionOptions<T>): UseCatalogListSelectionResult<T> {
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [selectionMode, setSelectionMode] = useState<CatalogSelectionMode | null>(null);

  const selectableRows = useMemo(
    () => rows.filter(isRowSelectable),
    [rows, isRowSelectable],
  );

  const selectedCount = selectionMode === 'all' ? totalCount : selectedIds.size;

  const singleAnchor = useMemo(() => {
    if (selectionMode === 'all' || selectedIds.size !== 1) return null;
    const id = [...selectedIds][0];
    return rows.find(r => getRowId(r) === id) ?? null;
  }, [rows, selectedIds, selectionMode, getRowId]);

  const isRowChecked = useCallback(
    (row: T) => selectionMode === 'all' || selectedIds.has(getRowId(row)),
    [getRowId, selectedIds, selectionMode],
  );

  const isPageAllSelected = selectableRows.length > 0
    && (selectionMode === 'all'
      || selectableRows.every(r => selectedIds.has(getRowId(r))));

  const toggleRow = useCallback(
    (row: T, checked: boolean) => {
      const id = getRowId(row);
      setSelectionMode(null);
      setSelectedIds(prev => {
        const next = new Set(prev);
        if (checked) next.add(id);
        else next.delete(id);
        return next;
      });
    },
    [getRowId],
  );

  const togglePageAll = useCallback(() => {
    setSelectionMode(null);
    const pageIds = selectableRows.map(getRowId);
    const allOnPage = pageIds.length > 0 && pageIds.every(id => selectedIds.has(id));
    if (allOnPage) {
      setSelectedIds(prev => {
        const next = new Set(prev);
        pageIds.forEach(id => next.delete(id));
        return next;
      });
    } else {
      setSelectedIds(prev => new Set([...prev, ...pageIds]));
    }
  }, [getRowId, selectableRows, selectedIds]);

  const selectAllInDatabase = useCallback(() => {
    setSelectionMode('all');
    setSelectedIds(new Set(selectableRows.map(getRowId)));
  }, [getRowId, selectableRows]);

  const clearSelection = useCallback(() => {
    setSelectionMode(null);
    setSelectedIds(new Set());
  }, []);

  const getBatchScope = useCallback(
    () => ({
      mode: selectionMode,
      ids: selectionMode === 'all' ? [] : [...selectedIds],
    }),
    [selectedIds, selectionMode],
  );

  return {
    selectedIds,
    selectionMode,
    selectedCount,
    singleAnchor,
    isRowChecked,
    isPageAllSelected,
    toggleRow,
    togglePageAll,
    selectAllInDatabase,
    clearSelection,
    getBatchScope,
  };
}
